  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const entry = map.get(t.userId);
    if (entry) {
      entry.total += t.amount;
      entry.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);
  return summaries.slice(0, n);
}
```

**Complexity:** O(n + m log m) where m = unique users ≪ n

---

### 5. `searchTransactions` — O(n²) → O(n)

**Problem:** `new RegExp(...)` constructed inside the loop for every transaction (O(n)). Linear dedup scan through results for every match (unnecessary — each transaction is visited exactly once, so duplicates are impossible).

**Fix:** Compile RegExp once before the loop; use `Array.filter()` (no dedup needed).

```typescript
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  // Compile once — outside the loop
  const pattern = new RegExp(
    query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"),
    "i"
  );
  return transactions.filter(t => pattern.test(t.description));
}
```

**Complexity:** O(n)
**Correctness notes:**
- Special regex characters still escaped (same escaping logic as original)
- Case-insensitive flag `"i"` preserved
- Dedup was logically redundant (each transaction object is only visited once in the loop), so removing it doesn't change results

---

### 6. `processAll` — no direct changes needed

`processAll` simply calls the other five functions. Once they are all optimized, the combined 200ms budget for 20k transactions will be easily met (each function will run in O(n) or O(n log n)).

The function body stays unchanged:
```typescript
export function processAll(transactions: Transaction[], topN: number = 10): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);
  return { categoryGroups, duplicates, topSpenders: topSpendersList };
}
```

