export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  if (transactions.length === 0) return [];

  // Sort so duplicates become adjacent — avoids building a string key for every
  // transaction (number→string conversion has GC cost at scale).
  const sorted = transactions.slice().sort((a, b) => {
    if (a.userId !== b.userId) return a.userId < b.userId ? -1 : 1;
    if (a.amount !== b.amount) return a.amount - b.amount;
    if (a.date !== b.date) return a.date < b.date ? -1 : 1;
    return 0;
  });

  const result: DuplicateGroup[] = [];
  let i = 0;
  while (i < sorted.length) {
    const t = sorted[i];
    let j = i + 1;
    // Advance j while the next transaction shares the same (userId, amount, date)
    while (
      j < sorted.length &&
      sorted[j].userId === t.userId &&
      sorted[j].amount === t.amount &&
      sorted[j].date === t.date
    ) {
      j++;
    }
    if (j > i + 1) {
      // Only build the key string for actual duplicate groups
      result.push({
        key: `${t.userId}|${t.amount}|${t.date}`,
        transactions: sorted.slice(i, j),
      });
    }
    i = j;
  }
  return result;
}

