import {
  Transaction,
  CategoryGroup,
  DuplicateGroup,
  RunningBalanceEntry,
  SpenderSummary,
  PipelineResult,
} from "./types.js";

/**
 * Groups transactions by category and calculates totals.
 *
 * KNOWN PERFORMANCE ISSUE: Uses array.find and array.filter instead of a Map,
 * and recalculates totals with reduce on every insert.
 */
export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
  const map = new Map<string, CategoryGroup>();

  for (const t of transactions) {
    const group = map.get(t.category);
    if (group) {
      group.transactions.push(t);
      group.total += t.amount;
    } else {
      map.set(t.category, {
        category: t.category,
        transactions: [t],
        total: t.amount,
      });
    }
  }

  return Array.from(map.values());
}

/**
 * Finds duplicate transactions (same userId + amount + date).
 *
 * KNOWN PERFORMANCE ISSUE: Compares every pair of transactions O(n^2).
 */
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  if (transactions.length === 0) return [];

  // Sort so duplicates become adjacent — avoids building a string key for every
  // transaction (number→string conversion has GC cost at scale).
  const sorted = transactions.slice().sort((a, b) => {
    if (a.userId !== b.userId) return a.userId < b.userId ? -1 : 1;
    if (a.amount !== b.amount) return a.amount - b.amount;
    if (a.date !== b.date) return a.date < b.date ? -1 : 1;
    return 0;
  });

  const result: DuplicateGroup[] = [];
  let i = 0;
  while (i < sorted.length) {
    const t = sorted[i];
    let j = i + 1;
    // Advance j while the next transaction shares the same (userId, amount, date)
    while (
      j < sorted.length &&
      sorted[j].userId === t.userId &&
      sorted[j].amount === t.amount &&
      sorted[j].date === t.date
    ) {
      j++;
    }
    if (j > i + 1) {
      // Only build the key string for actual duplicate groups
      result.push({
        key: `${t.userId}|${t.amount}|${t.date}`,
        transactions: sorted.slice(i, j),
      });
    }
    i = j;
  }
  return result;
}

/**
 * Calculates running balance for a specific user, sorted by date.
 *
 * KNOWN PERFORMANCE ISSUE: For each user transaction, rescans the entire
 * transactions array to re-filter and re-sort user transactions, then
 * recalculates the running balance from scratch.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  // Single O(n) filter
  const userTxns = transactions.filter((t) => t.userId === userId);
  // Single O(k log k) sort
  userTxns.sort((a, b) => a.date.localeCompare(b.date));

  // Single O(k) pass to build running balance
  let balance = 0;
  return userTxns.map((t) => {
    balance += t.amount;
    balance = Math.round(balance * 100) / 100;
    return {
      transactionId: t.id,
      amount: t.amount,
      balance,
      date: t.date,
    };
  });
}

/**
 * Returns the top N spenders.
 *
 * KNOWN PERFORMANCE ISSUE: For each unique user, rescans the entire
 * transactions array to calculate their total, then uses bubble sort.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  // Single O(n) pass to accumulate totals and counts per user
  const map = new Map<string, { total: number; count: number }>();
  for (const t of transactions) {
    const entry = map.get(t.userId);
    if (entry) {
      entry.total += t.amount;
      entry.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  // Build summaries array
  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  // O(m log m) native sort — far faster than bubble sort
  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 *
 * KNOWN PERFORMANCE ISSUE: Creates a new RegExp for every transaction
 * and does a linear dedup scan on the results array.
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  // Compile RegExp once, outside the loop
  const pattern = new RegExp(
    query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"),
    "i"
  );
  return transactions.filter((t) => pattern.test(t.description));
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

