/**
 * Runs the full processing pipeline.
 *
 * Fuses groupByCategory and topSpenders into a single pass to avoid
 * iterating the array three times; findDuplicates runs in a second pass.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  // Combined single pass: groupByCategory + topSpenders
  const categoryMap = new Map<string, CategoryGroup>();
  const spenderMap = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    // --- groupByCategory ---
    const catGroup = categoryMap.get(t.category);
    if (catGroup) {
      catGroup.transactions.push(t);
      catGroup.total += t.amount;
    } else {
      categoryMap.set(t.category, {
        category: t.category,
        transactions: [t],
        total: t.amount,
      });
    }

    // --- topSpenders ---
    const spender = spenderMap.get(t.userId);
    if (spender) {
      spender.total += t.amount;
      spender.count++;
    } else {
      spenderMap.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const categoryGroups = Array.from(categoryMap.values());

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of spenderMap) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }
  summaries.sort((a, b) => b.totalSpent - a.totalSpent);
