export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  // Single O(n) pass — indexed loop is JIT-friendly and avoids closure allocation
  const userTxns: Transaction[] = [];
  const n = transactions.length;
  for (let i = 0; i < n; i++) {
    if (transactions[i].userId === userId) {
      userTxns.push(transactions[i]);
    }
  }

  if (userTxns.length === 0) return [];

  // ISO date strings (YYYY-MM-DD) sort correctly with plain < / > — much faster
  // than localeCompare which invokes the ICU library for locale-aware comparison.
  userTxns.sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0));

  // Pre-allocated result array avoids repeated dynamic growth
  const k = userTxns.length;
  const result = new Array<RunningBalanceEntry>(k);
  let balance = 0;
  for (let i = 0; i < k; i++) {
    const t = userTxns[i];
    balance += t.amount;
    balance = Math.round(balance * 100) / 100;
    result[i] = {
      transactionId: t.id,
      amount: t.amount,
      balance,
      date: t.date,
    };
  }
  return result;
}

