  // Keys: userId (string) → date (string) → amount (number) → Transaction[]
  // String keys are existing in-memory strings (no new allocation per lookup).
  // Amount is stored as a number key — no toString() call per transaction.
  const outerMap = new Map<string, Map<string, Map<number, Transaction[]>>>();

  for (const t of transactions) {
    let byDate = outerMap.get(t.userId);
    if (!byDate) {
      byDate = new Map();
      outerMap.set(t.userId, byDate);
    }
    let byAmount = byDate.get(t.date);
    if (!byAmount) {
      byAmount = new Map();
      byDate.set(t.date, byAmount);
    }
    const group = byAmount.get(t.amount);
    if (group) {
      group.push(t);
    } else {
      byAmount.set(t.amount, [t]);
    }
  }

  // Only build the output key string for actual duplicate groups (far fewer than n)
  const result: DuplicateGroup[] = [];
  for (const [userId, byDate] of outerMap) {
    for (const [date, byAmount] of byDate) {
      for (const [amount, txns] of byAmount) {
        if (txns.length >= 2) {
          result.push({
            key: `${userId}|${amount}|${date}`,
            transactions: txns,
          });
        }
      }
