 * Calculates running balance for a specific user, sorted by date.
 *
 * KNOWN PERFORMANCE ISSUE: For each user transaction, rescans the entire
 * transactions array to re-filter and re-sort user transactions, then
 * recalculates the running balance from scratch.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  // Single O(n) filter
  const userTxns = transactions.filter((t) => t.userId === userId);
  // Single O(k log k) sort
  userTxns.sort((a, b) => a.date.localeCompare(b.date));

  // Single O(k) pass to build running balance
  let balance = 0;
  return userTxns.map((t) => {
    balance += t.amount;
    balance = Math.round(balance * 100) / 100;
